+        repo_path: "/tmp/repo",
+        timestamp: new Date().toISOString(),
+        commit_sha: "deadbeef",
+        commit_title: "Test commit",
+        branch: "main",
+      },
+    });
+
+    expect(response.status()).toBe(403);
+  });
+});

